"""Compatibility for The Fuck's 2016 tests under pytest 3.10.1."""

import os

import pytest


def pytest_configure(config):
    del config
    if pytest.__version__ != "3.10.1":
        raise RuntimeError("legacy pytest adapter requires pytest==3.10.1")
    from _pytest import runner

    if not hasattr(runner, "_update_current_test_var"):
        raise RuntimeError("pytest current-test hook is unavailable")

    def clear_current_test(_item, _when):
        os.environ.pop("PYTEST_CURRENT_TEST", None)

    runner._update_current_test_var = clear_current_test

